import json
import os

# Load the businesses data from file
businesses_file = var_functions.query_db:26
with open(businesses_file, 'r') as f:
    businesses = json.load(f)

# Extract categories from description field
def extract_categories(description):
    if not description:
        return []

    # Common patterns for categories in descriptions
    categories = []

    # Look for patterns like "services in X, Y, and Z" or "including X, Y, Z"
    desc_lower = description.lower()

    # Common category indicators
    if 'restaurant' in desc_lower or 'restaurants' in desc_lower:
        categories.append('Restaurants')
    if 'food' in desc_lower:
        categories.append('Food')
    if 'beauty' in desc_lower or 'salon' in desc_lower or 'spa' in desc_lower:
        categories.append('Beauty & Spas')
    if 'shopping' in desc_lower or 'shop' in desc_lower:
        categories.append('Shopping')
    if 'health' in desc_lower or 'medical' in desc_lower or 'doctor' in desc_lower:
        categories.append('Health & Medical')
    if 'education' in desc_lower:
        categories.append('Education')
    if 'active life' in desc_lower or 'fitness' in desc_lower:
        categories.append('Active Life')
    if 'nightlife' in desc_lower or 'bar' in desc_lower:
        categories.append('Nightlife')
    if 'home services' in desc_lower:
        categories.append('Home Services')
    if 'automotive' in desc_lower:
        categories.append('Automotive')
    if 'pets' in desc_lower:
        categories.append('Pets')
    if 'local services' in desc_lower:
        categories.append('Local Services')

    return categories

# Process all businesses
business_to_categories = {}
all_categories = set()

for business in businesses:
    business_id = business['business_id']
    description = business.get('description', '')
    cats = extract_categories(description)
    business_to_categories[business_id] = cats
    all_categories.update(cats)

print('__RESULT__:')
print(json.dumps({
    'total_businesses': len(businesses),
    'categories_found': list(all_categories),
    'sample_mappings': dict(list(business_to_categories.items())[:3])
}))

