import json

# Load reviews by 2016 users
reviews = var_functions.query_db:40

# Load businesses
businesses_path = var_functions.query_db:46
with open(businesses_path, 'r') as f:
    businesses = json.load(f)

# Create business_id to categories mapping
business_categories = {}
for business in businesses:
    business_id = business['business_id']
    description = business.get('description', '').lower()

    categories = []
    # Extract categories from description
    if 'education' in description:
        categories.append('Education')
    if 'elementary schools' in description:
        categories.append('Elementary Schools')
    if 'child care' in description or 'day care' in description:
        categories.append('Child Care & Day Care')
    if 'local services' in description:
        categories.append('Local Services')
    if 'preschools' in description:
        categories.append('Preschools')
    if 'montessori schools' in description:
        categories.append('Montessori Schools')
    if 'hair salons' in description:
        categories.append('Hair Salons')
    if 'beauty' in description or 'spas' in description:
        categories.append('Beauty & Spas')
    if 'hair stylists' in description:
        categories.append('Hair Stylists')
    if 'skin care' in description:
        categories.append('Skin Care')
    if 'blow dry' in description:
        categories.append('Blow Dry/Out Services')
    if 'makeup artists' in description:
        categories.append('Makeup Artists')
    if 'gun/rifle ranges' in description:
        categories.append('Gun/Rifle Ranges')
    if 'active life' in description:
        categories.append('Active Life')
    if 'internal medicine' in description:
        categories.append('Internal Medicine')
    if 'doctors' in description:
        categories.append('Doctors')
    if 'health' in description or 'medical' in description:
        categories.append('Health & Medical')
    if 'nail salons' in description:
        categories.append('Nail Salons')
    if 'hair removal' in description:
        categories.append('Hair Removal')
    if 'waxing' in description:
        categories.append('Waxing')

    business_categories[business_id] = categories

# Count reviews per category
category_counts = {}
for review in reviews:
    business_ref = review['business_ref']
    # Convert business_ref to business_id format
    business_id = business_ref.replace('businessref_', 'businessid_')

    categories = business_categories.get(business_id, [])
    for category in categories:
        category_counts[category] = category_counts.get(category, 0) + 1

# Get top 5 categories
top_5 = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:5]

